import json
import hashlib
import tempfile
import time
import threading

class ObjectCache:
    def __init__(self, cache_dir=None):
        self.cache_dir = cache_dir
        self.lock = threading.Lock()

    def _get_cache_file(self, key):
        if self.cache_dir is None:
            raise ValueError("Cache directory not specified")

        if not isinstance(key, str):
            raise ValueError("Key must be a string")

        cache_file = f"{self.cache_dir}/{hashlib.md5(key.encode()).hexdigest()}.json"
        return cache_file

    def _is_cache_stale(self, cache_file):
        try:
            with open(cache_file, 'rb') as f:
                data = json.load(f)
                if data['timestamp'] < time.time() - 60:
                    return True
        except (IOError, json.JSONDecodeError):
            return True
        return False

    def get(self, key):
        with self.lock:
            cache_file = self._get_cache_file(key)
            if self._is_cache_stale(cache_file):
                return None
            try:
                with open(cache_file, 'rb') as f:
                    return json.load(f)
            except (IOError, json.JSONDecodeError):
                return None

    def set(self, key, obj):
        with self.lock:
            cache_file = self._get_cache_file(key)
            if not self._is_cache_stale(cache_file):
                with open(cache_file, 'wb') as f:
                    json.dump({'timestamp': time.time(), 'obj': obj}, f)
            else:
                with open(cache_file, 'wb') as f:
                    json.dump({'timestamp': time.time(), 'obj': obj}, f)

    def delete(self, key):
        with self.lock:
            cache_file = self._get_cache_file(key)
            try:
                import shutil
                shutil.rmtree(cache_file)
            except (IOError, OSError):
                pass

def object_cache(key, obj):
    cache = ObjectCache()
    cache.set(key, obj)
    return cache.get(key)

