import os
import time
import watchdog.observers
import watchdog.events

class FileWatcher:
    def __init__(self, directory):
        self.directory = directory
        self.observer = None

    def start(self):
        self.observer = watchdog.observers.Observer()
        self.observer.schedule(watchdog.events.PatternMatchingEventHandler(), self.directory, recursive=True)
        self.observer.start()

    def stop(self):
        self.observer.stop()
        self.observer.join()

    def run(self):
        self.start()
        try:
            while True:
                time.sleep(1)
        except KeyboardInterrupt:
            self.stop()

    def on_created(self, event):
        print(f"File {event.src_path} created")

    def on_deleted(self, event):
        print(f"File {event.src_path} deleted")

    def on_modified(self, event):
        print(f"File {event.src_path} modified")

    def on_moved(self, event):
        print(f"File {event.src_path} moved to {event.dest_path}")


def file_watcher(directory):
    """
    A file watcher that detects changes to files in a directory.

    Args:
        directory (str): The directory to watch for changes.

    Returns:
        FileWatcher: An instance of the FileWatcher class.
    """
    return FileWatcher(directory)


