import os
import hashlib

def find_duplicate_files(directory):
    """
    This function finds duplicate files in a directory by comparing SHA-256 content hashes.

    Args:
        directory (str): The path to the directory to search for duplicates.

    Returns:
        dict: A dictionary where the keys are the paths to the duplicate files and the values are lists of paths to these files.
    """
    duplicates = {}
    for root, dirs, files in os.walk(directory):
        for file in files:
            file_path = os.path.join(root, file)
            try:
                with open(file_path, 'rb') as f:
                    hash = hashlib.sha256(f.read()).hexdigest()
                    if hash in duplicates:
                        duplicates[hash].append(file_path)
                    else:
                        duplicates[hash] = [file_path]
            except Exception as e:
                print(f"Error occurred while processing {file_path}: {e}")
    return {k: v for k, v in duplicates.items() if len(v) > 1}
